    void sendGameState(uint32_t target_player_id) {
        auto target_it = players.find(target_player_id);
        if (target_it == players.end()) return;

        size_t num_players = players.size();
        size_t total_size = sizeof(PacketHeader) + sizeof(GameStatePacket) +
                           num_players * sizeof(PlayerStatePacket);

        std::vector<uint8_t> buf(total_size);
        PacketHeader* pkt = (PacketHeader*)buf.data();
        pkt->type = PacketType::GAME_STATE;
        pkt->player_id = 0;
        pkt->sequence = global_sequence++;
        pkt->payload_size = (uint16_t)(sizeof(GameStatePacket) + num_players * sizeof(PlayerStatePacket));

        GameStatePacket* gs = (GameStatePacket*)(buf.data() + sizeof(PacketHeader));
        gs->num_players = (uint32_t)num_players;

        PlayerStatePacket* states = (PlayerStatePacket*)(buf.data() + sizeof(PacketHeader) + sizeof(GameStatePacket));
        int idx = 0;
        for (auto& [id, player] : players) {
            states[idx].player_id = player.id;
            states[idx].x = player.position.x;
            states[idx].y = player.position.y;
            states[idx].z = player.position.z;
            states[idx].yaw = player.yaw;
            states[idx].pitch = player.pitch;
            states[idx].health = player.health;
            states[idx].alive = player.alive ? 1 : 0;
            states[idx].weapon_id = player.current_weapon;
            idx++;
        }

        sendPacket(target_it->second.address, buf.data(), total_size);
    }

    void checkRespawns() {
        auto now = std::chrono::steady_clock::now();

        for (auto& [id, player] : players) {
            if (!player.alive && player.connected) {
                float time_since_death = std::chrono::duration<float>(now - player.death_time).count();
                if (time_since_death >= RESPAWN_TIME) {
                    player.alive = true;
                    player.health = MAX_HEALTH;
                    player.position = getRandomSpawnPoint();
                    player.velocity = Vector3(0, 0, 0);

                    std::cout << "Player '" << player.name << "' respawned at ("
                              << player.position.x << ", " << player.position.y
                              << ", " << player.position.z << ")" << std::endl;

                    // Send respawn to the player
                    uint8_t buf[sizeof(PacketHeader) + sizeof(RespawnPacket)];
                    PacketHeader* pkt = (PacketHeader*)buf;
                    pkt->type = PacketType::RESPAWN;
                    pkt->player_id = player.id;
                    pkt->sequence = global_sequence++;
                    pkt->payload_size = sizeof(RespawnPacket);

                    RespawnPacket* respawn = (RespawnPacket*)(buf + sizeof(PacketHeader));
                    respawn->player_id = player.id;
                    respawn->x = player.position.x;
                    respawn->y = player.position.y;
                    respawn->z = player.position.z;
                    respawn->health = player.health;

                    broadcastPacketToAll(buf, sizeof(buf));
                }
            }
        }
    }

    void checkTimeouts() {
        auto now = std::chrono::steady_clock::now();
        std::vector<uint32_t> timed_out;

        for (auto& [id, player] : players) {
            float elapsed = std::chrono::duration<float>(now - player.last_packet_time).count();
            if (elapsed > 30.0f) {
                timed_out.push_back(id);
            }
        }

        for (uint32_t id : timed_out) {
            std::string key = addressToKey(players[id].address);
            std::cout << "Player '" << players[id].name << "' timed out." << std::endl;

            uint8_t buf[sizeof(PacketHeader)];
            PacketHeader* pkt = (PacketHeader*)buf;
            pkt->type = PacketType::DISCONNECT;
            pkt->player_id = id;
            pkt->sequence = global_sequence++;
            pkt->payload_size = 0;
            broadcastPacketToAll(buf, sizeof(buf));

            players.erase(id);
            address_to_player.erase(key);
        }
    }

    void processPacket(const char* buffer, int bytes_received, const sockaddr_in& sender_addr) {
        if (bytes_received < (int)sizeof(PacketHeader)) return;

        PacketHeader header;
        memcpy(&header, buffer, sizeof(PacketHeader));

        const char* payload = buffer + sizeof(PacketHeader);
        int payload_size = bytes_received - sizeof(PacketHeader);

        switch (header.type) {
            case PacketType::CONNECT:
                if (payload_size >= (int)sizeof(ConnectPacket)) {
                    handleConnect(sender_addr, header, payload);
                }
                break;

            case PacketType::DISCONNECT:
                handleDisconnect(sender_addr, header);
                break;

            case PacketType::POSITION_UPDATE:
                if (payload_size >= (int)sizeof(PositionPacket)) {
                    handlePositionUpdate(sender_addr, header, payload);
                }
                break;

            case PacketType::SHOOT:
                if (payload_size >= (int)sizeof(ShootPacket)) {
                    handleShoot(sender_addr, header, payload);
                }
                break;

            default:
                break;
        }
    }

